package org.joda.time;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.joda.time.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.joda.time.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.joda.time.DateTimeZone;

public class StepDefs {

    private int hourOffset;
    private int minuteOffset;
    private DateTimeZone dateTimeZone;
    private Exception exception;

    @Given("the hour offset is {int}")
    public void the_hour_offset_is(int hour) {
        this.hourOffset = hour;
    }

    @Given("the minute offset is {int}")
    public void the_minute_offset_is(int minute) {
        this.minuteOffset = minute;
    }

    @When("I attempt to create a DateTimeZone with these offsets")
    public void i_attempt_to_create_a_DateTimeZone_with_these_offsets() {
        try {
            this.dateTimeZone = DateTimeZone.forOffsetHoursMinutes(hourOffset, minuteOffset);
            this.exception = null;
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("an IllegalArgumentException should be thrown")
    public void an_IllegalArgumentException_should_be_thrown() {
        assertNotNull("Expected IllegalArgumentException but none was thrown", exception);
        assertEquals("Wrong exception type thrown", IllegalArgumentException.class, exception.getClass());
    }

    @Then("a valid DateTimeZone should be created with ID {string}")
    public void a_valid_DateTimeZone_should_be_created_with_ID(String expectedId) {
        assertNull("Unexpected exception was thrown", exception);
        assertNotNull("DateTimeZone was not created", dateTimeZone);
        assertEquals("Wrong ID for created DateTimeZone", expectedId, dateTimeZone.getID());
    }
}
